def validate(args, output):
    a, b, c = args
    s = output
    # Empty is valid only when no letter can be placed
    # Check structural validity
    if 'aaa' in s or 'bbb' in s or 'ccc' in s:
        return False
    if s.count('a') > a or s.count('b') > b or s.count('c') > c:
        return False
    if any(ch not in 'abc' for ch in s):
        return False
    # Check maximality: can we append any character without violating?
    # If output is not maximal, try to find a letter we could still add.
    def can_add(s, counts, ch):
        if counts[ch] == 0:
            return False
        if len(s) >= 2 and s[-1] == ch and s[-2] == ch:
            return False
        return True
    counts = {'a': a - s.count('a'), 'b': b - s.count('b'), 'c': c - s.count('c')}
    for ch in 'abc':
        if can_add(s, counts, ch):
            return False  # not maximal
    return True

