function validate(args, output) {
    const [a, b, c] = args;
    const s = output;
    if (s.includes('aaa') || s.includes('bbb') || s.includes('ccc')) return false;
    let ca = 0, cb = 0, cc = 0;
    for (const ch of s) {
        if (ch === 'a') ca++;
        else if (ch === 'b') cb++;
        else if (ch === 'c') cc++;
        else return false;
    }
    if (ca > a || cb > b || cc > c) return false;
    const rem = {a: a - ca, b: b - cb, c: c - cc};
    function canAdd(s, rem, ch) {
        if (rem[ch] === 0) return false;
        if (s.length >= 2 && s[s.length-1] === ch && s[s.length-2] === ch) return false;
        return true;
    }
    for (const ch of ['a','b','c']) {
        if (canAdd(s, rem, ch)) return false;
    }
    return true;
}

