var longestDiverseString = function(a, b, c) {
    // Mirror Python's heapq (max-count first, alpha-first on tie)
    const counts = [['a', a], ['b', b], ['c', c]];
    function sortCounts() {
        counts.sort((x, y) => y[1] !== x[1] ? y[1] - x[1] : x[0] < y[0] ? -1 : 1);
    }
    const res = [];
    while (true) {
        sortCounts();
        const [ch1, cnt1] = counts[0];
        if (cnt1 === 0) break;
        if (res.length >= 2 && res[res.length-1] === ch1 && res[res.length-2] === ch1) {
            const [ch2, cnt2] = counts[1];
            if (cnt2 === 0) break;
            res.push(ch2);
            counts[1][1]--;
        } else {
            res.push(ch1);
            counts[0][1]--;
        }
    }
    return res.join('');
};
